<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ignore_changes</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [desired_capacity, target_group_arns]</span></span>
